esqlQuery.esql:
FROM logs-*
// Restrict to Azure Activity Logs (Administrative category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Administrative"
// Capture both Failure and Failed result types (Azure uses inconsistent casing)
| WHERE azure.result.type IN ("Failure", "Failed")
// Derive actor for grouping (user.name or principal ID)
| EVAL actor = COALESCE(user.name, azure.identity.authorization.evidence.principal.id, "unknown")
// Aggregate by operation and actor for context; adjust minimum count to reduce noise
| STATS failed_count = COUNT(*), sample_timestamps = VALUES(@timestamp) BY azure.operation.name, actor, network.peer.address
// Minimum failures to alert — tune based on environment noise
| WHERE failed_count >= 3
| SORT failed_count DESC
| LIMIT 20
